{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires deriving a general scaling exponent for dissipative PDEs based on the diffusion order s and dimension n, then verifying it against specific physical models.",
  "helpers": [
    {
      "label": "theoretical_derivation",
      "instructions": "Perform a formal dimensional analysis on a general dissipative PDE of the form partial_t u + (u dot grad) u + (-Delta)^s u = 0. Use scaling transformations u(x, t) = lambda^a u(lambda x, lambda^b t) to determine the critical exponent for the norm of u in terms of n and s. Derive the general formula for the De Giorgi exponent that characterizes the regularity threshold."
    },
    {
      "label": "boundary_case_verification",
      "instructions": "Apply the derived general formula for the De Giorgi exponent to the following specific cases: 3D Navier-Stokes (s=1, n=3), 2D Navier-Stokes (s=1, n=2), 1D Burgers (s=1, n=1), Surface Quasi-Geostrophic equation (SQG, s=1/2, n=2), Magnetohydrodynamics (MHD, s=1, n=3), and fractional Navier-Stokes (s, n). Confirm that the formula yields the known critical scaling exponents for each."
    },
    {
      "label": "parameter_consistency_check",
      "instructions": "Verify the behavior of the derived exponent formula as s approaches 0 and as n approaches infinity. Check if the formula maintains consistency with the scaling of the energy dissipation rate and the Sobolev embedding constants relevant to the regularity theory of these PDEs."
    }
  ],
  "synthesis_brief": "Combine the general formula derived by the first helper with the specific case verifications from the second helper. Use the third helper's consistency check to ensure the formula is robust across all parameter ranges. The final answer must be the general formula expressed in terms of n and s, followed by a justification showing its application to the six requested PDEs."
}

